module top_module(clk, en, reset, d, q);parameter WIDTH=1; 
  input clk; 
  input en; 
  input reset; 
  input [WIDTH-1:0] d; 
  output [WIDTH-1:0] q; 
  reg [WIDTH-1:0] q; 
    wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @ (posedge clk or posedge reset or posedge dbg_halt) 
  if (reset) 
  q <= 0; 
  else if (en) 
  q <= d; 
 endmodule
